{"content":"import {
	createSystem,
	World,
	PanelUI,
	PanelDocument,
	UIKitDocument,
	UIKit,
	Follower,
	InputComponent,
	Entity,
} from '@iwsdk/core';
import {
	BoxGeometry,
	MeshStandardMaterial,
	Mesh,
	Color,
	Vector3,
	Group,
	AmbientLight,
	DirectionalLight,
	PointLight,
	Object3D,
	AdditiveBlending,
	BufferGeometry,
	Float32BufferAttribute,
	PointsMaterial,
	Points,
	FogExp2,
} from 'three';

// ── Types ──────────────────────────────────────────────────────────────────

interface Block {
	entity: Entity;
	mesh: Mesh;
	width: number;
	depth: number;
	x: number;
	z: number;
	y: number;
}

interface FallingPiece {
	mesh: Mesh;
	velocity: Vector3;
	life: number;
}

interface Particle {
	mesh: Mesh;
	velocity: Vector3;
	life: number;
	maxLife: number;
}

type GameMode = 'classic' | 'zen' | 'speed' | 'precision' | 'challenge' | 'endless';
type GameState = 'menu' | 'mode_select' | 'playing' | 'paused' | 'game_over' | 'settings' | 'achievements' | 'tutorial' | 'stats';
type SlideAxis = 'x' | 'z';

interface Achievement {
	id: string;
	name: string;
	description: string;
	unlocked: boolean;
}

interface GameStats {
	gamesPlayed: number;
	totalBlocks: number;
	totalPerfects: number;
	bestHeight: number;
	bestCombo: number;
	bestScore: number;
	totalScore: number;
}

// ── Audio Engine ───────────────────────────────────────────────────────────

class AudioEngine {
	private ctx: AudioContext | null = null;
	private masterGain: GainNode | null = null;
	volume = 0.7;
	sfxEnabled = true;
	musicEnabled = true;
	private droneOsc: OscillatorNode | null = null;
	private droneGain: GainNode | null = null;

	private ensure(): AudioContext {
		if (!this.ctx) {
			this.ctx = new AudioContext();
			this.masterGain = this.ctx.createGain();
			this.masterGain.gain.value = this.volume;
			this.masterGain.connect(this.ctx.destination);
		}
		if (this.ctx.state === 'suspended') this.ctx.resume();
		return this.ctx;
	}

	setVolume(v: number) {
		this.volume = v;
		if (this.masterGain) this.masterGain.gain.value = v;
	}

	playPlace(perfect: boolean, combo: number) {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;

		// Base place sound
		const osc = ctx.createOscillator();
		const gain = ctx.createGain();
		osc.connect(gain);
		gain.connect(this.masterGain!);

		const baseFreq = 220 + combo * 30;
		osc.frequency.setValueAtTime(baseFreq, t);
		osc.frequency.exponentialRampToValueAtTime(baseFreq * (perfect ? 2 : 1.5), t + 0.1);
		osc.type = perfect ? 'sine' : 'triangle';
		gain.gain.setValueAtTime(0.3, t);
		gain.gain.exponentialRampToValueAtTime(0.001, t + (perfect ? 0.4 : 0.2));
		osc.start(t);
		osc.stop(t + 0.5);

		if (perfect) {
			// Arpeggio for perfects
			const notes = [baseFreq, baseFreq * 1.25, baseFreq * 1.5, baseFreq * 2];
			notes.forEach((freq, i) => {
				const o = ctx.createOscillator();
				const g = ctx.createGain();
				o.connect(g);
				g.connect(this.masterGain!);
				o.frequency.value = freq;
				o.type = 'sine';
				g.gain.setValueAtTime(0.15, t + i * 0.06);
				g.gain.exponentialRampToValueAtTime(0.001, t + i * 0.06 + 0.3);
				o.start(t + i * 0.06);
				o.stop(t + i * 0.06 + 0.35);
			});
		}
	}

	playCut() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		const osc = ctx.createOscillator();
		const gain = ctx.createGain();
		osc.connect(gain);
		gain.connect(this.masterGain!);
		osc.type = 'sawtooth';
		osc.frequency.setValueAtTime(400, t);
		osc.frequency.exponentialRampToValueAtTime(80, t + 0.15);
		gain.gain.setValueAtTime(0.15, t);
		gain.gain.exponentialRampToValueAtTime(0.001, t + 0.2);
		osc.start(t);
		osc.stop(t + 0.25);
	}

	playGameOver() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		[440, 349, 294, 220].forEach((freq, i) => {
			const osc = ctx.createOscillator();
			const gain = ctx.createGain();
			osc.connect(gain);
			gain.connect(this.masterGain!);
			osc.frequency.value = freq;
			osc.type = 'triangle';
			gain.gain.setValueAtTime(0.2, t + i * 0.15);
			gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.15 + 0.4);
			osc.start(t + i * 0.15);
			osc.stop(t + i * 0.15 + 0.5);
		});
	}

	playMenuSelect() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		const osc = ctx.createOscillator();
		const gain = ctx.createGain();
		osc.connect(gain);
		gain.connect(this.masterGain!);
		osc.frequency.setValueAtTime(880, t);
		osc.frequency.exponentialRampToValueAtTime(1320, t + 0.08);
		osc.type = 'sine';
		gain.gain.setValueAtTime(0.15, t);
		gain.gain.exponentialRampToValueAtTime(0.001, t + 0.12);
		osc.start(t);
		osc.stop(t + 0.15);
	}

	playCountdown() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		const osc = ctx.createOscillator();
		const gain = ctx.createGain();
		osc.connect(gain);
		gain.connect(this.masterGain!);
		osc.frequency.value = 660;
		osc.type = 'sine';
		gain.gain.setValueAtTime(0.2, t);
		gain.gain.exponentialRampToValueAtTime(0.001, t + 0.15);
		osc.start(t);
		osc.stop(t + 0.2);
	}

	playCountdownGo() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		const osc = ctx.createOscillator();
		const gain = ctx.createGain();
		osc.connect(gain);
		gain.connect(this.masterGain!);
		osc.frequency.value = 1320;
		osc.type = 'sine';
		gain.gain.setValueAtTime(0.3, t);
		gain.gain.exponentialRampToValueAtTime(0.001, t + 0.3);
		osc.start(t);
		osc.stop(t + 0.35);
	}

	startDrone() {
		if (!this.musicEnabled) return;
		const ctx = this.ensure();
		if (this.droneOsc) return;
		this.droneOsc = ctx.createOscillator();
		this.droneGain = ctx.createGain();
		this.droneOsc.connect(this.droneGain);
		this.droneGain.connect(this.masterGain!);
		this.droneOsc.type = 'sine';
		this.droneOsc.frequency.value = 55;
		this.droneGain.gain.value = 0.08;
		this.droneOsc.start();
	}

	stopDrone() {
		if (this.droneOsc) {
			this.droneOsc.stop();
			this.droneOsc.disconnect();
			this.droneOsc = null;
			this.droneGain = null;
		}
	}

	playAchievement() {
		if (!this.sfxEnabled) return;
		const ctx = this.ensure();
		const t = ctx.currentTime;
		[523, 659, 784, 1047].forEach((freq, i) => {
			const osc = ctx.createOscillator();
			const gain = ctx.createGain();
			osc.connect(gain);
			gain.connect(this.masterGain!);
			osc.frequency.value = freq;
			osc.type = 'sine';
			gain.gain.setValueAtTime(0.12, t + i * 0.08);
			gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.08 + 0.25);
			osc.start(t + i * 0.08);
			osc.stop(t + i * 0.08 + 0.3);
		});
	}
}

// ── Color Palette ──────────────────────────────────────────────────────────

const NEON_COLORS = [
	0x00ffff, 0xff00ff, 0x00ff88, 0xff4488, 0x44aaff,
	0xffaa00, 0xaa44ff, 0x88ff00, 0xff6644, 0x44ffaa,
];

function getBlockColor(index: number): number {
	return NEON_COLORS[index % NEON_COLORS.length];
}

// ── Constants ──────────────────────────────────────────────────────────────

const BLOCK_HEIGHT = 0.3;
const BASE_WIDTH = 3.0;
const BASE_DEPTH = 3.0;
const BASE_SPEED = 2.5;
const SPEED_INCREMENT = 0.08;
const MAX_SPEED = 8.0;
const PERFECT_THRESHOLD = 0.08;
const SLIDE_RANGE = 5.0;

// ── Main System ────────────────────────────────────────────────────────────

export class GameSystem extends createSystem({}) {
	// State
	private state: GameState = 'menu';
	private mode: GameMode = 'classic';
	private blocks: Block[] = [];
	private currentBlock: Block | null = null;
	private slideAxis: SlideAxis = 'x';
	private slideDir = 1;
	private slideSpeed = BASE_SPEED;
	private score = 0;
	private combo = 0;
	private maxCombo = 0;
	private height = 0;
	private gameTime = 0;
	private countdownTimer = 0;
	private isCountingDown = false;

	// Falling pieces
	private fallingPieces: FallingPiece[] = [];

	// Particles
	private particles: Particle[] = [];
	private particleGroup!: Group;

	// Scene
	private towerGroup!: Group;
	private gridFloor!: Group;
	private starField!: Points;

	// Audio
	private audio = new AudioEngine();

	// Panels
	private menuEntity: Entity | null = null;
	private hudEntity: Entity | null = null;
	private gameOverEntity: Entity | null = null;
	private pauseEntity: Entity | null = null;
	private settingsEntity: Entity | null = null;
	private achievementsEntity: Entity | null = null;
	private modeSelectEntity: Entity | null = null;
	private tutorialEntity: Entity | null = null;
	private statsEntity: Entity | null = null;
	private countdownEntity: Entity | null = null;

	// World ref
	private w!: World;

	// Achievements
	private achievements: Achievement[] = [];

	// Stats
	private stats: GameStats = {
		gamesPlayed: 0,
		totalBlocks: 0,
		totalPerfects: 0,
		bestHeight: 0,
		bestCombo: 0,
		bestScore: 0,
		totalScore: 0,
	};

	// Speed mode timer
	private speedTimeLeft = 60;

	// Challenge mode
	private challengeTarget = 0;

	// Camera follow
	private cameraTargetY = 5;
	private cameraCurrentY = 5;

	// Perfect streak text
	private perfectFlashTimer = 0;

	// Input debounce
	private placeCooldown = 0;

	bootstrap(world: World) {
		this.w = world;
		this.loadStats();
		this.loadAchievements();
		this.setupScene();
		this.setupPanels();
	}

	// ── Scene Setup ──────────────────────────────────────────────────────

	private setupScene() {
		const scene = this.w.scene;

		// Fog
		scene.fog = new FogExp2(0x050510, 0.015);
		scene.background = new Color(0x050510);

		// Lighting
		const ambient = new AmbientLight(0x334466, 0.6);
		scene.add(ambient);

		const dirLight = new DirectionalLight(0xffffff, 0.8);
		dirLight.position.set(5, 20, 10);
		scene.add(dirLight);

		const point1 = new PointLight(0x00ffff, 1, 30);
		point1.position.set(-5, 10, 5);
		scene.add(point1);

		const point2 = new PointLight(0xff00ff, 0.8, 30);
		point2.position.set(5, 15, -5);
		scene.add(point2);

		// Tower group
		this.towerGroup = new Group();
		scene.add(this.towerGroup);

		// Particle group
		this.particleGroup = new Group();
		scene.add(this.particleGroup);

		// Grid floor
		this.gridFloor = new Group();
		this.createGridFloor();
		scene.add(this.gridFloor);

		// Starfield
		this.createStarfield();
	}

	private createGridFloor() {
		const gridSize = 40;
		const divisions = 40;
		const step = gridSize / divisions;
		const halfSize = gridSize / 2;

		for (let i = 0; i <= divisions; i++) {
			const pos = -halfSize + i * step;
			const isMain = i % 5 === 0;

			// X-axis lines
			const xGeo = new BoxGeometry(gridSize, 0.005, 0.005);
			const xMat = new MeshStandardMaterial({
				color: isMain ? 0x00ffff : 0x112233,
				emissive: isMain ? 0x004455 : 0x050510,
			});
			const xLine = new Mesh(xGeo, xMat);
			xLine.position.set(0, 0, pos);
			this.gridFloor.add(xLine);

			// Z-axis lines
			const zGeo = new BoxGeometry(0.005, 0.005, gridSize);
			const zMat = new MeshStandardMaterial({
				color: isMain ? 0x00ffff : 0x112233,
				emissive: isMain ? 0x004455 : 0x050510,
			});
			const zLine = new Mesh(zGeo, zMat);
			zLine.position.set(pos, 0, 0);
			this.gridFloor.add(zLine);
		}
	}

	private createStarfield() {
		const count = 500;
		const positions = new Float32Array(count * 3);
		for (let i = 0; i < count; i++) {
			positions[i * 3] = (Math.random() - 0.5) * 100;
			positions[i * 3 + 1] = Math.random() * 80 + 5;
			positions[i * 3 + 2] = (Math.random() - 0.5) * 100;
		}
		const geo = new BufferGeometry();
		geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
		const mat = new PointsMaterial({
			color: 0xaabbff,
			size: 0.1,
			blending: AdditiveBlending,
			transparent: true,
			opacity: 0.6,
		});
		this.starField = new Points(geo, mat);
		this.w.scene.add(this.starField);
	}

	// ── Panel Setup ──────────────────────────────────────────────────────

	private setupPanels() {
		// Main menu — fixed in world
		this.menuEntity = this.w.createTransformEntity(new Object3D());
		this.menuEntity.object3D!.position.set(0, 5, -3);
		this.menuEntity.addComponent(PanelUI, { config: './ui/main-menu.json', width: 1.4, height: 1.6 });

		// HUD — follower
		this.hudEntity = this.w.createTransformEntity(new Object3D(), { parent: this.w.playerHeadEntity, persistent: true });
		this.hudEntity.addComponent(Follower, { offsetPosition: [0, 0.35, -1.2] });
		this.hudEntity.addComponent(PanelUI, { config: './ui/hud.json', width: 0.8, height: 0.25 });
		this.hudEntity.object3D!.visible = false;

		// Game over — fixed in world
		this.gameOverEntity = this.w.createTransformEntity(new Object3D());
		this.gameOverEntity.object3D!.position.set(0, 5, -3);
		this.gameOverEntity.addComponent(PanelUI, { config: './ui/game-over.json', width: 1.4, height: 1.6 });
		this.gameOverEntity.object3D!.visible = false;

		// Pause
		this.pauseEntity = this.w.createTransformEntity(new Object3D());
		this.pauseEntity.object3D!.position.set(0, 5, -3);
		this.pauseEntity.addComponent(PanelUI, { config: './ui/pause.json', width: 1.2, height: 1.0 });
		this.pauseEntity.object3D!.visible = false;

		// Settings
		this.settingsEntity = this.w.createTransformEntity(new Object3D());
		this.settingsEntity.object3D!.position.set(0, 5, -3);
		this.settingsEntity.addComponent(PanelUI, { config: './ui/settings.json', width: 1.2, height: 1.4 });
		this.settingsEntity.object3D!.visible = false;

		// Achievements
		this.achievementsEntity = this.w.createTransformEntity(new Object3D());
		this.achievementsEntity.object3D!.position.set(0, 5, -3);
		this.achievementsEntity.addComponent(PanelUI, { config: './ui/achievements.json', width: 1.4, height: 1.8 });
		this.achievementsEntity.object3D!.visible = false;

		// Mode select
		this.modeSelectEntity = this.w.createTransformEntity(new Object3D());
		this.modeSelectEntity.object3D!.position.set(0, 5, -3);
		this.modeSelectEntity.addComponent(PanelUI, { config: './ui/mode-select.json', width: 1.4, height: 1.6 });
		this.modeSelectEntity.object3D!.visible = false;

		// Tutorial
		this.tutorialEntity = this.w.createTransformEntity(new Object3D());
		this.tutorialEntity.object3D!.position.set(0, 5, -3);
		this.tutorialEntity.addComponent(PanelUI, { config: './ui/tutorial.json', width: 1.2, height: 1.2 });
		this.tutorialEntity.object3D!.visible = false;

		// Stats
		this.statsEntity = this.w.createTransformEntity(new Object3D());
		this.statsEntity.object3D!.position.set(0, 5, -3);
		this.statsEntity.addComponent(PanelUI, { config: './ui/stats.json', width: 1.2, height: 1.4 });
		this.statsEntity.object3D!.visible = false;

		// Countdown
		this.countdownEntity = this.w.createTransformEntity(new Object3D(), { parent: this.w.playerHeadEntity, persistent: true });
		this.countdownEntity.addComponent(Follower, { offsetPosition: [0, 0, -1.5] });
		this.countdownEntity.addComponent(PanelUI, { config: './ui/countdown.json', width: 0.6, height: 0.6 });
		this.countdownEntity.object3D!.visible = false;
	}

	// ── State Management ─────────────────────────────────────────────────

	private setState(newState: GameState) {
		// Hide all panels first
		if (this.menuEntity?.object3D) this.menuEntity.object3D.visible = false;
		if (this.hudEntity?.object3D) this.hudEntity.object3D.visible = false;
		if (this.gameOverEntity?.object3D) this.gameOverEntity.object3D.visible = false;
		if (this.pauseEntity?.object3D) this.pauseEntity.object3D.visible = false;
		if (this.settingsEntity?.object3D) this.settingsEntity.object3D.visible = false;
		if (this.achievementsEntity?.object3D) this.achievementsEntity.object3D.visible = false;
		if (this.modeSelectEntity?.object3D) this.modeSelectEntity.object3D.visible = false;
		if (this.tutorialEntity?.object3D) this.tutorialEntity.object3D.visible = false;
		if (this.statsEntity?.object3D) this.statsEntity.object3D.visible = false;
		if (this.countdownEntity?.object3D) this.countdownEntity.object3D.visible = false;

		this.state = newState;

		// Show relevant panels and position in world
		switch (newState) {
			case 'menu':
				if (this.menuEntity?.object3D) {
					this.menuEntity.object3D.visible = true;
					this.positionPanelAtTower(this.menuEntity);
				}
				break;
			case 'mode_select':
				if (this.modeSelectEntity?.object3D) {
					this.modeSelectEntity.object3D.visible = true;
					this.positionPanelAtTower(this.modeSelectEntity);
				}
				break;
			case 'playing':
				if (this.hudEntity?.object3D) this.hudEntity.object3D.visible = true;
				break;
			case 'paused':
				if (this.hudEntity?.object3D) this.hudEntity.object3D.visible = true;
				if (this.pauseEntity?.object3D) {
					this.pauseEntity.object3D.visible = true;
					this.positionPanelAtTower(this.pauseEntity);
				}
				break;
			case 'game_over':
				if (this.gameOverEntity?.object3D) {
					this.gameOverEntity.object3D.visible = true;
					this.positionPanelAtTower(this.gameOverEntity);
				}
				break;
			case 'settings':
				if (this.settingsEntity?.object3D) {
					this.settingsEntity.object3D.visible = true;
					this.positionPanelAtTower(this.settingsEntity);
				}
				break;
			case 'achievements':
				if (this.achievementsEntity?.object3D) {
					this.achievementsEntity.object3D.visible = true;
					this.positionPanelAtTower(this.achievementsEntity);
				}
				break;
			case 'tutorial':
				if (this.tutorialEntity?.object3D) {
					this.tutorialEntity.object3D.visible = true;
					this.positionPanelAtTower(this.tutorialEntity);
				}
				break;
			case 'stats':
				if (this.statsEntity?.object3D) {
					this.statsEntity.object3D.visible = true;
					this.positionPanelAtTower(this.statsEntity);
				}
				break;
		}
	}

	private positionPanelAtTower(entity: Entity) {
		if (!entity.object3D) return;
		const y = Math.max(5, this.cameraCurrentY);
		entity.object3D.position.set(0, y, -3);
	}

	// ── Game Logic ───────────────────────────────────────────────────────

	private startGame(mode: GameMode) {
		this.mode = mode;
		this.score = 0;
		this.combo = 0;
		this.maxCombo = 0;
		this.height = 0;
		this.gameTime = 0;
		this.slideSpeed = BASE_SPEED;
		this.slideAxis = 'x';
		this.slideDir = 1;
		this.speedTimeLeft = 60;
		this.perfectFlashTimer = 0;
		this.placeCooldown = 0;

		if (mode === 'challenge') {
			this.challengeTarget = 15 + Math.floor(Math.random() * 20);
		}

		// Clear tower
		this.clearTower();

		// Create base block
		this.createBaseBlock();

		// Start countdown
		this.isCountingDown = true;
		this.countdownTimer = 3;
		if (this.countdownEntity?.object3D) this.countdownEntity.object3D.visible = true;
		if (this.hudEntity?.object3D) this.hudEntity.object3D.visible = true;
		this.updateCountdownPanel();

		this.audio.startDrone();
	}

	private clearTower() {
		// Remove all block entities
		for (const block of this.blocks) {
			if (block.entity.object3D) {
				this.towerGroup.remove(block.entity.object3D);
			}
		}
		this.blocks = [];
		this.currentBlock = null;

		// Remove falling pieces
		for (const fp of this.fallingPieces) {
			this.towerGroup.remove(fp.mesh);
		}
		this.fallingPieces = [];

		// Remove particles
		for (const p of this.particles) {
			this.particleGroup.remove(p.mesh);
		}
		this.particles = [];

		this.cameraTargetY = 5;
		this.cameraCurrentY = 5;
	}

	private createBaseBlock() {
		const geo = new BoxGeometry(BASE_WIDTH, BLOCK_HEIGHT, BASE_DEPTH);
		const mat = new MeshStandardMaterial({
			color: getBlockColor(0),
			emissive: getBlockColor(0),
			emissiveIntensity: 0.3,
			metalness: 0.7,
			roughness: 0.3,
		});
		const mesh = new Mesh(geo, mat);
		const entity = this.w.createTransformEntity(mesh);
		mesh.position.set(0, BLOCK_HEIGHT / 2, 0);
		this.towerGroup.add(mesh);

		this.blocks.push({
			entity,
			mesh,
			width: BASE_WIDTH,
			depth: BASE_DEPTH,
			x: 0,
			z: 0,
			y: BLOCK_HEIGHT / 2,
		});

		this.height = 1;
	}

	private spawnSlidingBlock() {
		const prev = this.blocks[this.blocks.length - 1];
		const color = getBlockColor(this.blocks.length);

		const geo = new BoxGeometry(prev.width, BLOCK_HEIGHT, prev.depth);
		const mat = new MeshStandardMaterial({
			color,
			emissive: color,
			emissiveIntensity: 0.4,
			metalness: 0.7,
			roughness: 0.3,
		});
		const mesh = new Mesh(geo, mat);
		const entity = this.w.createTransformEntity(mesh);

		const y = prev.y + BLOCK_HEIGHT;
		const startPos = this.slideAxis === 'x' ? -SLIDE_RANGE : -SLIDE_RANGE;
		mesh.position.set(
			this.slideAxis === 'x' ? startPos : prev.x,
			y,
			this.slideAxis === 'z' ? startPos : prev.z,
		);
		this.towerGroup.add(mesh);

		this.currentBlock = {
			entity,
			mesh,
			width: prev.width,
			depth: prev.depth,
			x: mesh.position.x,
			z: mesh.position.z,
			y,
		};

		this.slideDir = 1;

		// Alternate axis
		this.slideAxis = this.slideAxis === 'x' ? 'z' : 'x';
	}

	private placeBlock() {
		if (!this.currentBlock || this.placeCooldown > 0) return;
		this.placeCooldown = 0.2;

		const current = this.currentBlock;
		const prev = this.blocks[this.blocks.length - 1];

		let overlapX: number, overlapZ: number;
		let offsetX: number, offsetZ: number;

		if (this.slideAxis === 'z') {
			// Was sliding on X (axis toggles before this call? No — slideAxis was toggled in spawn)
			// Actually slideAxis was already toggled when spawning. The block was sliding on the PREVIOUS axis.
			// Let me reconsider: spawn toggles axis, then the block slides on the new axis.
			// Wait — spawn sets slideAxis = opposite, then block slides on that axis. So if slideAxis is now 'z',
			// the block was sliding on 'z'. Hmm, let me re-read spawn:
			// In spawn, we set this.slideAxis = this.slideAxis === 'x' ? 'z' : 'x'
			// Then the block slides on the NEW slideAxis. So when placing, slideAxis is the axis the block was sliding on.
			// Wait no — we toggle at spawn time. So if it was 'x', it becomes 'z', and the block slides on 'z'.
			// But the mesh position uses: this.slideAxis === 'x' ? startPos : prev.x for x-coord
			// and this.slideAxis === 'z' ? startPos : prev.z for z-coord.
			// After toggle, if slideAxis='z', x = prev.x, z = startPos. Block slides on Z.
			// So when placing with slideAxis='z', the block was indeed sliding on Z.

			offsetX = current.mesh.position.x - prev.x;
			offsetZ = current.mesh.position.z - prev.z;

			// Overlap on Z axis (the sliding axis)
			overlapZ = prev.depth - Math.abs(offsetZ);
			overlapX = prev.width; // Full overlap on non-sliding axis

			if (overlapZ <= 0) {
				this.gameOver();
				return;
			}
		} else {
			// slideAxis = 'x', block was sliding on X
			offsetX = current.mesh.position.x - prev.x;
			offsetZ = current.mesh.position.z - prev.z;

			overlapX = prev.width - Math.abs(offsetX);
			overlapZ = prev.depth;

			if (overlapX <= 0) {
				this.gameOver();
				return;
			}
		}

		// Check for perfect placement
		const isPerfect = Math.abs(this.slideAxis === 'z' ? offsetZ : offsetX) < PERFECT_THRESHOLD;

		if (isPerfect) {
			// Perfect — keep full size
			current.mesh.position.x = prev.x;
			current.mesh.position.z = prev.z;
			current.width = prev.width;
			current.depth = prev.depth;
			this.combo++;
			this.score += 10 + this.combo * 5;

			// Perfect particles
			this.spawnPerfectParticles(current.mesh.position);

			// Grow block slightly on long combos
			if (this.combo >= 5 && this.mode !== 'precision') {
				const grow = 0.05;
				current.width = Math.min(BASE_WIDTH, current.width + grow);
				current.depth = Math.min(BASE_DEPTH, current.depth + grow);
			}

			this.perfectFlashTimer = 1.0;
			this.audio.playPlace(true, this.combo);
			this.stats.totalPerfects++;
		} else {
			// Cut the overhanging piece
			this.combo = 0;
			this.score += 5;

			if (this.slideAxis === 'z') {
				// Cut on Z
				const newZ = prev.z + (offsetZ > 0 ? (overlapZ / 2 - prev.depth / 2) : -(overlapZ / 2 - prev.depth / 2));
				// Wait let me recalculate:
				// The overlap center in Z: overlap region starts at max(current_min_z, prev_min_z) and ends at min(current_max_z, prev_max_z)
				const curMinZ = current.mesh.position.z - current.depth / 2;
				const curMaxZ = current.mesh.position.z + current.depth / 2;
				const prevMinZ = prev.z - prev.depth / 2;
				const prevMaxZ = prev.z + prev.depth / 2;
				const overlapMinZ = Math.max(curMinZ, prevMinZ);
				const overlapMaxZ = Math.min(curMaxZ, prevMaxZ);
				const overlapCenterZ = (overlapMinZ + overlapMaxZ) / 2;
				const overlapSizeZ = overlapMaxZ - overlapMinZ;

				// Falling piece
				const cutMinZ = offsetZ > 0 ? overlapMaxZ : curMinZ;
				const cutMaxZ = offsetZ > 0 ? curMaxZ : overlapMinZ;
				const cutSize = cutMaxZ - cutMinZ;
				const cutCenter = (cutMinZ + cutMaxZ) / 2;

				if (cutSize > 0.01) {
					this.spawnFallingPiece(
						current.mesh.position.x,
						current.y,
						cutCenter,
						current.width,
						cutSize,
						getBlockColor(this.blocks.length),
					);
				}

				// Resize current block to overlap
				current.mesh.position.z = overlapCenterZ;
				current.depth = overlapSizeZ;
				current.z = overlapCenterZ;
				current.x = current.mesh.position.x;
			} else {
				// Cut on X
				const curMinX = current.mesh.position.x - current.width / 2;
				const curMaxX = current.mesh.position.x + current.width / 2;
				const prevMinX = prev.x - prev.width / 2;
				const prevMaxX = prev.x + prev.width / 2;
				const overlapMinX = Math.max(curMinX, prevMinX);
				const overlapMaxX = Math.min(curMaxX, prevMaxX);
				const overlapCenterX = (overlapMinX + overlapMaxX) / 2;
				const overlapSizeX = overlapMaxX - overlapMinX;

				const cutMinX = offsetX > 0 ? overlapMaxX : curMinX;
				const cutMaxX = offsetX > 0 ? curMaxX : overlapMinX;
				const cutSize = cutMaxX - cutMinX;
				const cutCenter = (cutMinX + cutMaxX) / 2;

				if (cutSize > 0.01) {
					this.spawnFallingPiece(
						cutCenter,
						current.y,
						current.mesh.position.z,
						cutSize,
						current.depth,
						getBlockColor(this.blocks.length),
					);
				}

				current.mesh.position.x = overlapCenterX;
				current.width = overlapSizeX;
				current.x = overlapCenterX;
				current.z = current.mesh.position.z;
			}

			// Rebuild geometry for new size
			current.mesh.geometry.dispose();
			current.mesh.geometry = new BoxGeometry(current.width, BLOCK_HEIGHT, current.depth);

			this.audio.playPlace(false, 0);
			this.audio.playCut();
		}

		if (this.combo > this.maxCombo) this.maxCombo = this.combo;
		current.x = current.mesh.position.x;
		current.z = current.mesh.position.z;

		this.blocks.push(current);
		this.currentBlock = null;
		this.height = this.blocks.length;
		this.stats.totalBlocks++;

		// Increase speed
		this.slideSpeed = Math.min(MAX_SPEED, BASE_SPEED + (this.height - 1) * SPEED_INCREMENT);

		// Update camera target
		this.cameraTargetY = Math.max(5, current.y + 3);

		// Check achievements
		this.checkAchievements();

		// Update HUD
		this.updateHUD();

		// Check game over for very small blocks
		if (current.width < 0.1 || current.depth < 0.1) {
			this.gameOver();
			return;
		}

		// Check challenge mode win
		if (this.mode === 'challenge' && this.height >= this.challengeTarget) {
			this.score += 100;
			this.gameOver();
			return;
		}

		// Spawn next
		this.spawnSlidingBlock();
	}

	private spawnFallingPiece(x: number, y: number, z: number, width: number, depth: number, color: number) {
		const geo = new BoxGeometry(width, BLOCK_HEIGHT, depth);
		const mat = new MeshStandardMaterial({
			color,
			emissive: color,
			emissiveIntensity: 0.3,
			metalness: 0.7,
			roughness: 0.3,
			transparent: true,
		});
		const mesh = new Mesh(geo, mat);
		mesh.position.set(x, y, z);
		this.towerGroup.add(mesh);

		this.fallingPieces.push({
			mesh,
			velocity: new Vector3(
				(Math.random() - 0.5) * 1,
				0,
				(Math.random() - 0.5) * 1,
			),
			life: 2,
		});
	}

	private spawnPerfectParticles(pos: Vector3) {
		const count = 20;
		for (let i = 0; i < count; i++) {
			const geo = new BoxGeometry(0.05, 0.05, 0.05);
			const mat = new MeshStandardMaterial({
				color: 0xffffff,
				emissive: 0xffffff,
				emissiveIntensity: 1,
				transparent: true,
			});
			const mesh = new Mesh(geo, mat);
			mesh.position.copy(pos);
			this.particleGroup.add(mesh);

			const angle = (i / count) * Math.PI * 2;
			const speed = 2 + Math.random() * 3;
			this.particles.push({
				mesh,
				velocity: new Vector3(
					Math.cos(angle) * speed,
					(Math.random() - 0.3) * speed,
					Math.sin(angle) * speed,
				),
				life: 1.0,
				maxLife: 1.0,
			});
		}
	}

	private gameOver() {
		this.audio.stopDrone();
		this.audio.playGameOver();

		this.stats.gamesPlayed++;
		this.stats.totalScore += this.score;
		if (this.score > this.stats.bestScore) this.stats.bestScore = this.score;
		if (this.height > this.stats.bestHeight) this.stats.bestHeight = this.height;
		if (this.maxCombo > this.stats.bestCombo) this.stats.bestCombo = this.maxCombo;
		this.saveStats();

		this.checkAchievements();
		this.updateGameOverPanel();
		this.setState('game_over');
	}

	// ── Update ───────────────────────────────────────────────────────────

	update(delta: number, _time: number) {
		this.placeCooldown = Math.max(0, this.placeCooldown - delta);

		// Handle countdown
		if (this.isCountingDown) {
			this.countdownTimer -= delta;
			this.updateCountdownPanel();
			if (this.countdownTimer <= 0) {
				this.isCountingDown = false;
				if (this.countdownEntity?.object3D) this.countdownEntity.object3D.visible = false;
				this.setState('playing');
				this.spawnSlidingBlock();
			}
			// Update camera during countdown
			this.updateCamera(delta);
			return;
		}

		// Handle input
		this.handleInput();

		// Update game logic
		if (this.state === 'playing') {
			this.gameTime += delta;

			// Slide current block
			if (this.currentBlock) {
				const slideAx = this.slideAxis === 'z' ? 'z' : 'x';
				const pos = this.currentBlock.mesh.position;

				if (slideAx === 'x') {
					pos.x += this.slideSpeed * this.slideDir * delta;
					if (pos.x > SLIDE_RANGE) { pos.x = SLIDE_RANGE; this.slideDir = -1; }
					if (pos.x < -SLIDE_RANGE) { pos.x = -SLIDE_RANGE; this.slideDir = 1; }
				} else {
					pos.z += this.slideSpeed * this.slideDir * delta;
					if (pos.z > SLIDE_RANGE) { pos.z = SLIDE_RANGE; this.slideDir = -1; }
					if (pos.z < -SLIDE_RANGE) { pos.z = -SLIDE_RANGE; this.slideDir = 1; }
				}
			}

			// Speed mode timer
			if (this.mode === 'speed') {
				this.speedTimeLeft -= delta;
				if (this.speedTimeLeft <= 0) {
					this.gameOver();
				}
			}

			// Perfect flash timer
			if (this.perfectFlashTimer > 0) {
				this.perfectFlashTimer -= delta;
			}
		}

		// Update falling pieces
		this.updateFallingPieces(delta);

		// Update particles
		this.updateParticles(delta);

		// Update camera
		this.updateCamera(delta);

		// Animate starfield
		if (this.starField) {
			this.starField.rotation.y += delta * 0.005;
		}
	}

	private updateFallingPieces(delta: number) {
		for (let i = this.fallingPieces.length - 1; i >= 0; i--) {
			const fp = this.fallingPieces[i];
			fp.velocity.y -= 9.8 * delta;
			fp.mesh.position.add(fp.velocity.clone().multiplyScalar(delta));
			fp.mesh.rotation.x += delta * 2;
			fp.mesh.rotation.z += delta * 1.5;
			fp.life -= delta;

			const mat = fp.mesh.material as MeshStandardMaterial;
			mat.opacity = Math.max(0, fp.life / 2);

			if (fp.life <= 0 || fp.mesh.position.y < -10) {
				this.towerGroup.remove(fp.mesh);
				fp.mesh.geometry.dispose();
				mat.dispose();
				this.fallingPieces.splice(i, 1);
			}
		}
	}

	private updateParticles(delta: number) {
		for (let i = this.particles.length - 1; i >= 0; i--) {
			const p = this.particles[i];
			p.velocity.y -= 5 * delta;
			p.mesh.position.add(p.velocity.clone().multiplyScalar(delta));
			p.life -= delta;

			const mat = p.mesh.material as MeshStandardMaterial;
			mat.opacity = Math.max(0, p.life / p.maxLife);
			const scale = p.life / p.maxLife;
			p.mesh.scale.setScalar(scale);

			if (p.life <= 0) {
				this.particleGroup.remove(p.mesh);
				p.mesh.geometry.dispose();
				mat.dispose();
				this.particles.splice(i, 1);
			}
		}
	}

	private updateCamera(delta: number) {
		this.cameraCurrentY += (this.cameraTargetY - this.cameraCurrentY) * delta * 3;
		this.w.camera.position.set(0, this.cameraCurrentY, 8);
		this.w.camera.lookAt(0, this.cameraCurrentY - 2, 0);

		// Update world-space panel positions to follow camera height
		if (this.state === 'game_over' && this.gameOverEntity?.object3D) {
			this.gameOverEntity.object3D.position.y = this.cameraCurrentY;
		}
		if (this.state === 'paused' && this.pauseEntity?.object3D) {
			this.pauseEntity.object3D.position.y = this.cameraCurrentY;
		}
	}

	// ── Input ────────────────────────────────────────────────────────────

	private handleInput() {
		const kb = this.w.input.keyboard;
		const rightGp = this.w.input.xr.gamepads.right;
		const leftGp = this.w.input.xr.gamepads.left;

		const triggerDown = rightGp?.getButtonDown(InputComponent.Trigger)
			|| leftGp?.getButtonDown(InputComponent.Trigger);
		const aDown = rightGp?.getButtonDown(InputComponent.A_Button)
			|| leftGp?.getButtonDown(InputComponent.A_Button);
		const bDown = rightGp?.getButtonDown(InputComponent.B_Button)
			|| leftGp?.getButtonDown(InputComponent.B_Button);

		switch (this.state) {
			case 'playing':
				// Place block
				if (kb.getKeyDown('Space') || triggerDown || aDown) {
					this.placeBlock();
				}
				// Pause
				if (kb.getKeyDown('Escape') || bDown) {
					this.setState('paused');
				}
				break;

			case 'paused':
				if (kb.getKeyDown('Escape') || bDown) {
					this.setState('playing');
				}
				break;
		}
	}

	// ── Panel Updates ────────────────────────────────────────────────────

	private getDoc(entity: Entity | null): UIKitDocument | undefined {
		if (!entity) return undefined;
		return entity.getValue(PanelDocument, 'document') as UIKitDocument | undefined;
	}

	private updateHUD() {
		const doc = this.getDoc(this.hudEntity);
		if (!doc) return;

		const scoreEl = doc.getElementById('score') as UIKit.Text | undefined;
		const comboEl = doc.getElementById('combo') as UIKit.Text | undefined;
		const heightEl = doc.getElementById('height') as UIKit.Text | undefined;

		scoreEl?.setProperties({ text: `${this.score}` });
		comboEl?.setProperties({ text: this.combo > 0 ? `x${this.combo}` : '' });
		heightEl?.setProperties({ text: `${this.height}` });

		if (this.mode === 'speed') {
			const timerEl = doc.getElementById('timer') as UIKit.Text | undefined;
			timerEl?.setProperties({ text: `${Math.ceil(this.speedTimeLeft)}s` });
		}
	}

	private updateGameOverPanel() {
		const doc = this.getDoc(this.gameOverEntity);
		if (!doc) return;

		const scoreEl = doc.getElementById('final-score') as UIKit.Text | undefined;
		const heightEl = doc.getElementById('final-height') as UIKit.Text | undefined;
		const comboEl = doc.getElementById('final-combo') as UIKit.Text | undefined;
		const bestEl = doc.getElementById('best-score') as UIKit.Text | undefined;

		scoreEl?.setProperties({ text: `${this.score}` });
		heightEl?.setProperties({ text: `${this.height}` });
		comboEl?.setProperties({ text: `${this.maxCombo}` });
		bestEl?.setProperties({ text: `${this.stats.bestScore}` });
	}

	private updateCountdownPanel() {
		const doc = this.getDoc(this.countdownEntity);
		if (!doc) return;

		const countEl = doc.getElementById('count') as UIKit.Text | undefined;
		const num = Math.ceil(this.countdownTimer);
		if (num > 0) {
			countEl?.setProperties({ text: `${num}` });
			this.audio.playCountdown();
		} else {
			countEl?.setProperties({ text: 'GO!' });
			this.audio.playCountdownGo();
		}
	}

	private updateSettingsPanel() {
		const doc = this.getDoc(this.settingsEntity);
		if (!doc) return;
		const volEl = doc.getElementById('volume-val') as UIKit.Text | undefined;
		volEl?.setProperties({ text: `${Math.round(this.audio.volume * 100)}%` });
		const sfxEl = doc.getElementById('sfx-val') as UIKit.Text | undefined;
		sfxEl?.setProperties({ text: this.audio.sfxEnabled ? 'ON' : 'OFF' });
		const musicEl = doc.getElementById('music-val') as UIKit.Text | undefined;
		musicEl?.setProperties({ text: this.audio.musicEnabled ? 'ON' : 'OFF' });
	}

	private updateAchievementsPanel() {
		const doc = this.getDoc(this.achievementsEntity);
		if (!doc) return;

		const unlocked = this.achievements.filter((a) => a.unlocked).length;
		const totalEl = doc.getElementById('ach-total') as UIKit.Text | undefined;
		totalEl?.setProperties({ text: `${unlocked} / ${this.achievements.length}` });

		// Update first 12 visible achievement slots
		for (let i = 0; i < 12 && i < this.achievements.length; i++) {
			const a = this.achievements[i];
			const nameEl = doc.getElementById(`ach-name-${i}`) as UIKit.Text | undefined;
			const descEl = doc.getElementById(`ach-desc-${i}`) as UIKit.Text | undefined;
			nameEl?.setProperties({ text: a.unlocked ? a.name : '???' });
			descEl?.setProperties({ text: a.unlocked ? a.description : 'Locked' });
		}
	}

	private updateStatsPanel() {
		const doc = this.getDoc(this.statsEntity);
		if (!doc) return;

		const setField = (id: string, val: string) => {
			const el = doc.getElementById(id) as UIKit.Text | undefined;
			el?.setProperties({ text: val });
		};

		setField('stat-games', `${this.stats.gamesPlayed}`);
		setField('stat-blocks', `${this.stats.totalBlocks}`);
		setField('stat-perfects', `${this.stats.totalPerfects}`);
		setField('stat-best-height', `${this.stats.bestHeight}`);
		setField('stat-best-combo', `${this.stats.bestCombo}`);
		setField('stat-best-score', `${this.stats.bestScore}`);
		setField('stat-total-score', `${this.stats.totalScore}`);
		const pct = this.stats.totalBlocks > 0
			? ((this.stats.totalPerfects / this.stats.totalBlocks) * 100).toFixed(1)
			: '0.0';
		setField('stat-perfect-pct', `${pct}%`);
	}

	// ── Panel Button Handlers (via qualify event) ────────────────────────

	init() {
		// Wire panel buttons via qualify subscription — but we use bootstrap instead.
		// Panel button wiring happens in setupPanelHandlers called after panels load.
		// We'll poll for doc readiness and wire handlers.
	}

	private panelHandlersWired = new Set<string>();

	private tryWirePanelHandlers() {
		// Main menu
		if (!this.panelHandlersWired.has('menu')) {
			const doc = this.getDoc(this.menuEntity);
			if (doc) {
				this.panelHandlersWired.add('menu');
				this.wireButton(doc, 'btn-play', () => { this.audio.playMenuSelect(); this.setState('mode_select'); });
				this.wireButton(doc, 'btn-settings', () => { this.audio.playMenuSelect(); this.updateSettingsPanel(); this.setState('settings'); });
				this.wireButton(doc, 'btn-achievements', () => { this.audio.playMenuSelect(); this.updateAchievementsPanel(); this.setState('achievements'); });
				this.wireButton(doc, 'btn-tutorial', () => { this.audio.playMenuSelect(); this.setState('tutorial'); });
				this.wireButton(doc, 'btn-stats', () => { this.audio.playMenuSelect(); this.updateStatsPanel(); this.setState('stats'); });
			}
		}

		// Mode select
		if (!this.panelHandlersWired.has('mode_select')) {
			const doc = this.getDoc(this.modeSelectEntity);
			if (doc) {
				this.panelHandlersWired.add('mode_select');
				this.wireButton(doc, 'btn-classic', () => { this.audio.playMenuSelect(); this.startGame('classic'); });
				this.wireButton(doc, 'btn-zen', () => { this.audio.playMenuSelect(); this.startGame('zen'); });
				this.wireButton(doc, 'btn-speed', () => { this.audio.playMenuSelect(); this.startGame('speed'); });
				this.wireButton(doc, 'btn-precision', () => { this.audio.playMenuSelect(); this.startGame('precision'); });
				this.wireButton(doc, 'btn-challenge', () => { this.audio.playMenuSelect(); this.startGame('challenge'); });
				this.wireButton(doc, 'btn-endless', () => { this.audio.playMenuSelect(); this.startGame('endless'); });
				this.wireButton(doc, 'btn-mode-back', () => { this.audio.playMenuSelect(); this.setState('menu'); });
			}
		}

		// Game over
		if (!this.panelHandlersWired.has('game_over')) {
			const doc = this.getDoc(this.gameOverEntity);
			if (doc) {
				this.panelHandlersWired.add('game_over');
				this.wireButton(doc, 'btn-retry', () => { this.audio.playMenuSelect(); this.startGame(this.mode); });
				this.wireButton(doc, 'btn-menu', () => { this.audio.playMenuSelect(); this.clearTower(); this.setState('menu'); });
			}
		}

		// Pause
		if (!this.panelHandlersWired.has('pause')) {
			const doc = this.getDoc(this.pauseEntity);
			if (doc) {
				this.panelHandlersWired.add('pause');
				this.wireButton(doc, 'btn-resume', () => { this.audio.playMenuSelect(); this.setState('playing'); });
				this.wireButton(doc, 'btn-pause-menu', () => { this.audio.playMenuSelect(); this.audio.stopDrone(); this.clearTower(); this.setState('menu'); });
			}
		}

		// Settings
		if (!this.panelHandlersWired.has('settings')) {
			const doc = this.getDoc(this.settingsEntity);
			if (doc) {
				this.panelHandlersWired.add('settings');
				this.wireButton(doc, 'btn-vol-up', () => { this.audio.setVolume(Math.min(1, this.audio.volume + 0.1)); this.updateSettingsPanel(); });
				this.wireButton(doc, 'btn-vol-down', () => { this.audio.setVolume(Math.max(0, this.audio.volume - 0.1)); this.updateSettingsPanel(); });
				this.wireButton(doc, 'btn-sfx-toggle', () => { this.audio.sfxEnabled = !this.audio.sfxEnabled; this.updateSettingsPanel(); });
				this.wireButton(doc, 'btn-music-toggle', () => { this.audio.musicEnabled = !this.audio.musicEnabled; this.updateSettingsPanel(); });
				this.wireButton(doc, 'btn-settings-back', () => { this.audio.playMenuSelect(); this.setState('menu'); });
			}
		}

		// Achievements
		if (!this.panelHandlersWired.has('achievements')) {
			const doc = this.getDoc(this.achievementsEntity);
			if (doc) {
				this.panelHandlersWired.add('achievements');
				this.wireButton(doc, 'btn-ach-back', () => { this.audio.playMenuSelect(); this.setState('menu'); });
			}
		}

		// Tutorial
		if (!this.panelHandlersWired.has('tutorial')) {
			const doc = this.getDoc(this.tutorialEntity);
			if (doc) {
				this.panelHandlersWired.add('tutorial');
				this.wireButton(doc, 'btn-tutorial-back', () => { this.audio.playMenuSelect(); this.setState('menu'); });
			}
		}

		// Stats
		if (!this.panelHandlersWired.has('stats')) {
			const doc = this.getDoc(this.statsEntity);
			if (doc) {
				this.panelHandlersWired.add('stats');
				this.wireButton(doc, 'btn-stats-back', () => { this.audio.playMenuSelect(); this.setState('menu'); });
			}
		}
	}

	private wireButton(doc: UIKitDocument, id: string, handler: () => void) {
		const btn = doc.getElementById(id);
		if (btn) {
			btn.addEventListener('click', handler);
		}
	}

